#include<bits/stdc++.h>
using namespace std;
long long n,m,Q,u,v,T;
struct node
{
    long long val,y;
    bool operator<(const node&b)const
    {
        return val<b.val;
    }
};
queue<long long> q[4];
long long a[100010];
int main()
{
    // priority_queue<node> q;
    scanf("%lld%lld%lld%lld%lld%lld",&n,&m,&Q,&u,&v,&T);
    for(long long i=1;i<=n;i++)
    {
        long long x;
        scanf("%lld",&x);
        a[i]=x;
    }
    sort(a+1,a+1+n,greater<int>());
    for(int i=1;i<=n;i++)
    {
        q[1].push(a[i]);
    }
    for(long long i=1;i<=m;i++)
    {
        long long t;
        long long flag=-1;
        for(long long j=1;j<=3;j++)
        {
            if(!q[j].empty()&&(flag==-1||t<q[j].front()))
            {
                t=q[j].front();
                flag=j;
            }
        }
        q[flag].pop();
        if(i%T==0)
        {
            printf("%lld ",t+(i-1)*Q);
        }
        long long tmp=(t+(i-1)*Q)*u/v;
        long long t1=tmp-i*Q;
        long long t2=t+(i-1)*Q-tmp-i*Q;
        // printf("%lld -> %lld %lld\n",t+(i-1)*Q,t1+i*Q,t2+i*Q);
        q[2].push(t1);
        q[3].push(t2);
    }
    printf("\n");
    for(long long i=1;i<=n+m;i++)
    {
        long long t;
        long long flag=-1;
        for(long long j=1;j<=3;j++)
        {
            if(!q[j].empty()&&(flag==-1||t<q[j].front()))
            {
                t=q[j].front();
                flag=j;
            }
        }
        if(i%T==0)
        {
            printf("%lld ",t+m*Q);
        }
        q[flag].pop();
    }
    return 0;
}
